// Process raw data into word objects
const wordsOrdered = raw.map(([img, en, zh, category, level, sentence, sentenceZh, tier, concept, subcategory, id, langs]) => ({
  id, en, zh, category, level, sentence, sentenceZh, img, tier, concept, subcategory, langs,
}));

// Seeded shuffle so order is stable per session but randomized across sessions
function shuffleArray(arr) {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

// all-pool: the words shown under the "all" scope. Excludes the 'specific'
// tier (names/events live only in their own category) and de-dups by concept
// — concept override if present, else English+Chinese. The representative
// prefers the 'core' tier. Category pools keep the FULL `words` list
// (marketing included, no de-dup).
function conceptKey(w) {
  return w.concept || (w.en.toLowerCase().trim() + '|' + w.zh.trim());
}
function buildAllPool(list) {
  const rep = new Map();
  for (const w of list) {
    if (w.tier === 'specific') continue;
    const k = conceptKey(w);
    const cur = rep.get(k);
    if (!cur) { rep.set(k, w); continue; }
    if (cur.tier !== 'core' && w.tier === 'core') rep.set(k, w);
  }
  return list.filter(w => w.tier !== 'specific' && rep.get(conceptKey(w)) === w);
}

export const words = wordsOrdered;
export const wordsShuffled = shuffleArray(wordsOrdered);
export const wordsAllPool = buildAllPool(wordsOrdered);
export const wordsAllPoolShuffled = shuffleArray(wordsAllPool);
export const categories = ['all', ...Object.keys(categoryLabels).filter(k => k !== 'all')];
